from __future__ import annotations
import argparse,json
from pathlib import Path
import sys
import numpy as np
R=Path(__file__).resolve().parents[1];sys.path.insert(0,str(R/'src'))
from spectral_capacity_transport import normalized_metrics,transport_factor_bounds  # noqa:E402
def main():
 p=argparse.ArgumentParser();p.add_argument('--smoke',action='store_true');a=p.parse_args();n=128 if a.smoke else 4096;rng=np.random.default_rng(124124 if a.smoke else 124);rows=[]
 for i in range(n):
  s=np.sort(10**rng.uniform(-2,1,8))[::-1];m=10**rng.uniform(-3,-.1);M=10**rng.uniform(.1,3);scale=rng.uniform(np.sqrt(m),np.sqrt(M),8);sp=np.sort(s*scale)[::-1];x=normalized_metrics(s);y=normalized_metrics(sp);f=transport_factor_bounds(m,M);rows.append({'q4_ratio':y['q4']/x['q4'],'capacity_ratio':y['capacity23']/x['capacity23'],'volume_ratio':y['normalized_four_volume']/x['normalized_four_volume'],'q4_lower':f['q4_lower_factor'],'q4_upper':f['q4_upper_factor'],'capacity_lower':f['capacity_lower_factor'],'capacity_upper':f['capacity_upper_factor'],'volume_lower':f['volume_lower_factor'],'volume_upper':f['volume_upper_factor']})
 s=np.array([100.,10.,1.,.1]);m,M=.25,4.;f=transport_factor_bounds(m,M);x=normalized_metrics(s);sc=np.array([100.,1.,.5,.1]);xc=normalized_metrics(sc);sharp={'q4':normalized_metrics(s*np.array([np.sqrt(M),1,1,np.sqrt(m)]))['q4']/x['q4'],'volume':normalized_metrics(s*np.array([np.sqrt(M),np.sqrt(m),np.sqrt(m),np.sqrt(m)]))['normalized_four_volume']/x['normalized_four_volume'],'capacity_upper':normalized_metrics(sc*np.array([np.sqrt(m),np.sqrt(M),np.sqrt(M),1]))['capacity23']/xc['capacity23'],'expected':f}
 summary={'sample_count':n,'q4_failure_count':sum(not(r['q4_lower']<=r['q4_ratio']+2e-12 and r['q4_ratio']<=r['q4_upper']+2e-12) for r in rows),'capacity_failure_count':sum(not(r['capacity_lower']<=r['capacity_ratio']+2e-12 and r['capacity_ratio']<=r['capacity_upper']+2e-12) for r in rows),'volume_failure_count':sum(not(r['volume_lower']<=r['volume_ratio']+2e-12 and r['volume_ratio']<=r['volume_upper']+2e-12) for r in rows),'sharp_failure_count':sum((abs(sharp['q4']-f['q4_lower_factor'])>1e-12,abs(sharp['volume']-f['volume_lower_factor'])>1e-12,abs(sharp['capacity_upper']-f['capacity_upper_factor'])>1e-12)),'minimum_direct_to_separate_gain':min(r['q4_lower']/((r['volume_lower']/r['capacity_upper'])) for r in rows),'maximum_direct_to_separate_gain':max(r['q4_lower']/((r['volume_lower']/r['capacity_upper'])) for r in rows)}
 payload={'status':'rh124_spectral_normalization_capacity_transport_audit','records':rows,'sharp_records':sharp,'audit_summary':summary,'theorem_boundary':{'two_sided_singular_transport':True,'sharp_q4_capacity_volume_factors':True,'separate_factor_loss_quantified':True,'all_level_gram_comparability_proved':False,'uniform_stage_A_closed':False,'hilbert_polya_operator':False,'riemann_hypothesis':False},'route_consequence':'Two-sided operator-Gram comparability transports q4, three-mode capacity, and normalized four-volume with sharp powers of m/M. Treating volume and capacity as independent black boxes loses an extra factor (m/M)^2 relative to direct q4 transport.'}
 o=R/'results'/('spectral_transport_smoke.json' if a.smoke else 'spectral_transport_audit.json');o.write_text(json.dumps(payload,indent=2,sort_keys=True)+'\n');print(json.dumps({'output':str(o.relative_to(R)),**summary},sort_keys=True))
if __name__=='__main__':main()
